import { useCart } from '../context/CartContext';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Minus, ShoppingBag } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';

const Cart = () => {
    const { cart, isCartOpen, setIsCartOpen, removeFromCart, updateQuantity, clearCart, cartTotal } = useCart();
    const navigate = useNavigate();

    // Prevent propagation when clicking inside the cart panel
    const stopPropagation = (e) => e.stopPropagation();

    return (
        <AnimatePresence>
            {isCartOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={() => setIsCartOpen(false)}
                        className="fixed inset-0 bg-dark/60 backdrop-blur-sm z-[60]"
                    />

                    {/* Cart Sidebar */}
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'tween', duration: 0.4 }}
                        onClick={stopPropagation}
                        className="fixed top-0 right-0 h-full w-full md:w-[450px] bg-cream shadow-2xl z-[70] flex flex-col pt-safe"
                    >
                        <div className="flex items-center justify-between p-6 border-b border-dark/10">
                            <h2 className="font-heading text-2xl text-dark">Your Cart</h2>
                            <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-black/5 rounded-full transition-colors text-dark">
                                <X strokeWidth={1.5} className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="flex-grow overflow-y-auto p-6 flex flex-col gap-6">
                            {cart.length === 0 ? (
                                <div className="flex flex-col items-center justify-center h-full text-dark/50 gap-4">
                                    <ShoppingBag strokeWidth={1} className="w-16 h-16" />
                                    <p className="font-sans uppercase tracking-widest text-sm">Your cart is empty</p>
                                    <button
                                        onClick={() => setIsCartOpen(false)}
                                        className="cursor-pointer mt-4 px-8 py-3 bg-[#C2B280] text-dark uppercase tracking-[0.2em] text-xs font-medium hover:bg-[#A8986B] transition-colors border border-transparent hover:border-dark/10"
                                    >
                                        Continue Shopping
                                    </button>
                                </div>
                            ) : (
                                cart.map(item => (
                                    <div key={item._id} className="flex gap-4 border-b border-dark/5 pb-6">
                                        <div className="w-24 h-24 bg-beige flex-shrink-0 relative overflow-hidden">
                                            <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                                        </div>
                                        <div className="flex flex-col flex-grow text-dark">
                                            <h3 className="text-[11px] font-medium uppercase tracking-[0.1em] line-clamp-2 leading-relaxed mb-2">
                                                {item.name}
                                            </h3>
                                            <p className="text-dark/70 text-sm mb-3">
                                                {typeof item.price === 'string' ? item.price : `RS. ${item.price}`}
                                            </p>
                                            <div className="flex items-center justify-between mt-auto">
                                                <div className="flex items-center border border-dark/20 text-dark">
                                                    <button onClick={() => updateQuantity(item._id, item.quantity - 1)} className="p-1.5 px-3 hover:bg-dark/5 transition-colors"><Minus strokeWidth={1.5} className="w-3 h-3" /></button>
                                                    <span className="text-xs px-2 w-6 text-center">{item.quantity}</span>
                                                    <button onClick={() => updateQuantity(item._id, item.quantity + 1)} className="p-1.5 px-3 hover:bg-dark/5 transition-colors"><Plus strokeWidth={1.5} className="w-3 h-3" /></button>
                                                </div>
                                                <button onClick={() => removeFromCart(item._id)} className="text-[10px] uppercase tracking-widest text-dark/40 hover:text-dark transition-colors underline underline-offset-4 pointer-cursor">
                                                    Remove
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>

                        {cart.length > 0 && (
                            <div className="p-6 border-t border-dark/10 bg-ivory">
                                <div className="flex justify-between items-center mb-6 text-dark font-heading text-xl">
                                    <span>Subtotal</span>
                                    <span>RS. {cartTotal.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                                </div>
                                <button
                                    onClick={() => {
                                        setIsCartOpen(false);
                                        navigate('/checkout');
                                    }}
                                    className="cursor-pointer w-full py-4 bg-[#C2B280] text-dark hover:bg-[#A8986B] transition-colors text-sm uppercase tracking-[0.2em] font-medium border border-transparent hover:border-dark/10 flex justify-center items-center gap-2"
                                >
                                    Checkout
                                </button>
                                <p className="text-center text-[10px] text-dark/50 mt-4 uppercase tracking-[0.15em]">Shipping & taxes calculated at checkout</p>
                            </div>
                        )}
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
};

export default Cart;

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageSquare, X, Send, Loader2, Sparkles } from 'lucide-react';

const Chatbot = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState([
        { role: 'model', content: "Welcome to Koto. I am your personal tea sommelier. How may I guide your sensory journey today?" }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const sendMessage = async (e) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg = { role: 'user', content: input };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:5000';
            const response = await fetch(`${API_URL}/api/chat`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ messages: [...messages, userMsg] })
            });

            if (!response.ok) {
                throw new Error('API Error');
            }

            const data = await response.json();
            setMessages(prev => [...prev, data]);
        } catch (error) {
            setMessages(prev => [...prev, { role: 'model', content: "Pardon me, I am momentarily unable to connect to my tea knowledge base. Please check back shortly." }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <>
            {/* Floating Button */}
            <motion.button
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                className="cursor-pointer fixed bottom-6 right-6 z-50 p-4 bg-[#C2B280] text-dark rounded-full shadow-2xl border border-dark/10 hover:bg-[#A8986B] transition-colors"
                onClick={() => setIsOpen(true)}
            >
                <MessageSquare strokeWidth={1.5} className="w-6 h-6" />
            </motion.button>

            {/* Chat Window */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: 20, scale: 0.95 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 20, scale: 0.95 }}
                        transition={{ duration: 0.3, ease: [0.16, 1, 0.3, 1] }}
                        className="fixed bottom-24 right-6 w-80 md:w-96 h-[500px] z-50 glass flex flex-col rounded-2xl overflow-hidden shadow-2xl border border-white/40"
                    >
                        {/* Header */}
                        <div className="bg-forest text-cream p-4 flex justify-between items-center border-b border-gold/20">
                            <div className="flex items-center gap-2">
                                <Sparkles className="w-5 h-5 text-gold" />
                                <h3 className="font-heading tracking-wider">AI Sommelier</h3>
                            </div>
                            <button onClick={() => setIsOpen(false)} className="text-cream/70 hover:text-cream transition-colors">
                                <X strokeWidth={1.5} className="w-5 h-5" />
                            </button>
                        </div>

                        {/* Messages */}
                        <div className="flex-grow p-4 overflow-y-auto bg-cream/50 flex flex-col gap-4">
                            {messages.map((msg, index) => (
                                <div
                                    key={index}
                                    className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${msg.role === 'user'
                                        ? 'bg-gold text-forest rounded-br-sm self-end'
                                        : 'bg-white border border-gray-100 text-forest rounded-bl-sm self-start shadow-sm'
                                        }`}
                                >
                                    {msg.content}
                                </div>
                            ))}
                            {isLoading && (
                                <div className="bg-white border border-gray-100 text-forest p-3 rounded-2xl rounded-bl-sm self-start w-fit shadow-sm">
                                    <Loader2 className="w-4 h-4 animate-spin text-gold" />
                                </div>
                            )}
                            <div ref={messagesEndRef} />
                        </div>

                        {/* Input */}
                        <form onSubmit={sendMessage} className="p-3 bg-white border-t border-gray-100 flex gap-2">
                            <input
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                placeholder="Ask about our teas..."
                                className="flex-grow bg-cream/50 border border-gray-200 rounded-full px-4 py-2 text-sm outline-none focus:border-gold focus:ring-1 focus:ring-gold transition-all"
                            />
                            <button
                                type="submit"
                                disabled={isLoading}
                                className="p-2 bg-forest text-gold rounded-full hover:bg-forest-dark transition-colors disabled:opacity-50"
                            >
                                <Send strokeWidth={1.5} className="w-4 h-4" />
                            </button>
                        </form>
                    </motion.div>
                )}
            </AnimatePresence>
        </>
    );
};

export default Chatbot;

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-router-dom';
import { ArrowRight, ChevronLeft, ChevronRight } from 'lucide-react';

const slides = [
    {
        id: 1,
        image: "https://images.unsplash.com/photo-1576092768241-dec231879fc3?auto=format&fit=crop&q=80",
        subtitle: "The Art of Infusion",
        title: "Experience the\nArt of Tea",
        link: "/collection",
        linkText: "Explore Collection"
    },
    {
        id: 2,
        image: "https://images.unsplash.com/photo-1544787219-7f47ccb76574?auto=format&fit=crop&q=80",
        subtitle: "Heritage & Craft",
        title: "Pioneers of\nOrganic Tea",
        link: "/about",
        linkText: "Our Story"
    },
    {
        id: 3,
        image: "https://images.unsplash.com/photo-1515823662972-da6a2e4d3002?auto=format&fit=crop&q=80",
        subtitle: "Pure Origins",
        title: "From Mountain\nTo Cup",
        link: "/collection",
        linkText: "Shop Single Origin"
    }
];

const HeroCarousel = ({ yImage, yText, opacity }) => {
    const [current, setCurrent] = useState(0);

    useEffect(() => {
        const timer = setInterval(() => {
            setCurrent((prev) => (prev + 1) % slides.length);
        }, 6000);
        return () => clearInterval(timer);
    }, []);

    const nextSlide = () => setCurrent((prev) => (prev + 1) % slides.length);
    const prevSlide = () => setCurrent((prev) => (prev - 1 + slides.length) % slides.length);

    return (
        <div className="relative h-screen w-full overflow-hidden flex items-center justify-center group bg-black" style={{ perspective: "1000px" }}>
            <AnimatePresence initial={false}>
                <motion.div
                    key={current}
                    initial={{ opacity: 0, scale: 1.05 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 1.5, ease: "easeInOut" }}
                    className="absolute inset-0 z-0"
                >
                    <motion.div style={{ y: yImage }} className="absolute inset-0 w-full h-full">
                        {/* More dynamic gradient overlay for depth */}
                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-black/60 z-10 transition-colors duration-500"></div>
                        <img
                            src={slides[current].image}
                            alt="Hero background"
                            className="w-full h-[120%] object-cover object-center transform scale-105"
                        />
                    </motion.div>
                </motion.div>
            </AnimatePresence>

            <AnimatePresence mode="wait">
                <motion.div
                    key={current}
                    style={{ y: yText, opacity, transformStyle: "preserve-3d" }}
                    className="relative z-20 text-center text-cream px-4 max-w-4xl mx-auto flex flex-col items-center drop-shadow-2xl"
                >
                    <motion.span
                        initial={{ opacity: 0, y: 30, rotateX: 45, z: -50 }}
                        animate={{ opacity: 1, y: 0, rotateX: 0, z: 0 }}
                        exit={{ opacity: 0, y: -20, rotateX: -45, z: -50 }}
                        transition={{ duration: 1, ease: "easeOut" }}
                        className="uppercase tracking-[0.4em] text-xs md:text-sm mb-6 text-gold/90 font-medium font-sans drop-shadow-md"
                        style={{ textShadow: "0px 2px 10px rgba(0,0,0,0.5)" }}
                    >
                        {slides[current].subtitle}
                    </motion.span>
                    <motion.h1
                        initial={{ opacity: 0, y: 50, rotateX: 20, z: -100 }}
                        animate={{ opacity: 1, y: 0, rotateX: 0, z: 0 }}
                        exit={{ opacity: 0, y: -40, rotateX: -20, z: -100 }}
                        transition={{ duration: 1.2, ease: "easeOut", delay: 0.1 }}
                        className="font-heading text-6xl md:text-8xl lg:text-9xl text-white mb-10 font-light whitespace-pre-line leading-[1.1] tracking-tight"
                        style={{
                            textShadow: "0px 10px 30px rgba(0,0,0,0.8), 0px 4px 10px rgba(0,0,0,0.4), 0px 1px 2px rgba(255,255,255,0.2)"
                        }}
                    >
                        {slides[current].title}
                    </motion.h1>
                    <motion.div
                        initial={{ opacity: 0, y: 20, z: -50 }}
                        animate={{ opacity: 1, y: 0, z: 0 }}
                        exit={{ opacity: 0, y: -20, z: -50 }}
                        transition={{ duration: 1, ease: "easeOut", delay: 0.3 }}
                    >
                        <Link
                            to={slides[current].link}
                            className="group/btn relative inline-flex items-center gap-4 px-8 py-4 bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/20 hover:border-white/40 rounded-full text-sm uppercase tracking-widest text-white transition-all duration-500 overflow-hidden shadow-[0_8px_32px_rgba(0,0,0,0.3)] hover:shadow-[0_16px_48px_rgba(0,0,0,0.5)] transform hover:-translate-y-1 hover:scale-105"
                        >
                            <span className="relative z-10">{slides[current].linkText}</span>
                            <div className="relative z-10 w-8 h-8 rounded-full bg-gold/80 group-hover:bg-gold flex items-center justify-center transition-colors duration-300">
                                <ArrowRight className="w-4 h-4 text-black" strokeWidth={2} />
                            </div>
                        </Link>
                    </motion.div>
                </motion.div>
            </AnimatePresence>

            {/* Navigation Buttons (Glassmorphic) */}
            <button
                onClick={prevSlide}
                className="absolute left-4 md:left-12 z-30 p-4 bg-black/20 text-white/80 hover:text-white backdrop-blur-xl border border-white/10 hover:border-white/30 rounded-full transition-all duration-500 transform hover:scale-110 shadow-[0_8px_32px_rgba(0,0,0,0.3)] opacity-0 group-hover:opacity-100 translate-x-4 group-hover:translate-x-0"
            >
                <ChevronLeft className="w-6 h-6" strokeWidth={1.5} />
            </button>
            <button
                onClick={nextSlide}
                className="absolute right-4 md:right-12 z-30 p-4 bg-black/20 text-white/80 hover:text-white backdrop-blur-xl border border-white/10 hover:border-white/30 rounded-full transition-all duration-500 transform hover:scale-110 shadow-[0_8px_32px_rgba(0,0,0,0.3)] opacity-0 group-hover:opacity-100 -translate-x-4 group-hover:translate-x-0"
            >
                <ChevronRight className="w-6 h-6" strokeWidth={1.5} />
            </button>

            {/* Pagination Dots (3D Style) */}
            <div className="absolute bottom-10 z-30 flex gap-4 p-4 rounded-full bg-black/20 backdrop-blur-xl border border-white/10 shadow-[0_8px_32px_rgba(0,0,0,0.3)]">
                {slides.map((_, i) => (
                    <button
                        key={i}
                        onClick={() => setCurrent(i)}
                        className={`h-2 rounded-full transition-all duration-500 ease-in-out relative flex items-center justify-center ${current === i
                            ? 'w-10 bg-gold shadow-[0_0_10px_var(--color-gold)]'
                            : 'w-2 bg-white/40 hover:bg-white/80'
                            }`}
                        aria-label={`Go to slide ${i + 1}`}
                    />
                ))}
            </div>
        </div>
    );
};

export default HeroCarousel;

import { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { ShoppingBag, Menu, X, Leaf } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '../context/CartContext';

const Navbar = () => {
    const [isScrolled, setIsScrolled] = useState(false);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const location = useLocation();
    const { cartCount, setIsCartOpen } = useCart();

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const navLinks = [
        { name: 'Collection', path: '/collection' },
        { name: 'Our Story', path: '/about' },
        { name: 'Contact', path: '/contact' },
    ];

    return (
        <motion.header
            initial={{ y: -100 }}
            animate={{ y: 0 }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className={`fixed top-0 w-full z-50 transition-all duration-500 py-4 ${isScrolled
                ? 'glass !py-2 shadow-sm text-forest'
                : location.pathname === '/'
                    ? 'bg-transparent text-cream'
                    : 'glass !py-2 text-forest'
                }`}
        >
            <div className="max-w-7xl mx-auto px-6 md:px-12 flex items-center justify-between">
                <Link to="/" className="flex items-center gap-2 group">
                    <Leaf strokeWidth={1.5} className="w-6 h-6 transform group-hover:-rotate-12 transition-transform duration-300" />
                    <span className="font-heading text-2xl tracking-widest uppercase">Koto</span>
                </Link>

                {/* Desktop Nav */}
                <nav className="hidden md:flex items-center gap-10">
                    {navLinks.map((link) => (
                        <Link
                            key={link.name}
                            to={link.path}
                            className={`text-sm uppercase tracking-widest hover:text-gold transition-colors duration-300 ${location.pathname === link.path ? 'text-gold' : ''
                                }`}
                        >
                            {link.name}
                        </Link>
                    ))}
                </nav>

                {/* Icons */}
                <div className="flex items-center gap-6">
                    <button onClick={() => setIsCartOpen(true)} className="relative group p-2 cursor-pointer">
                        <ShoppingBag strokeWidth={1.5} className="w-5 h-5 hover:text-gold transition-colors" />
                        {cartCount > 0 && (
                            <span className="absolute top-0 right-0 w-4 h-4 bg-gold rounded-full flex items-center justify-center text-[10px] text-white">
                                {cartCount}
                            </span>
                        )}
                    </button>

                    <button
                        className="md:hidden"
                        onClick={() => setMobileMenuOpen(true)}
                    >
                        <Menu strokeWidth={1.5} className="w-6 h-6 hover:text-gold transition-colors" />
                    </button>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {mobileMenuOpen && (
                    <motion.div
                        initial={{ opacity: 0, x: '100%' }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: '100%' }}
                        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
                        className="fixed inset-0 bg-forest text-cream z-50 flex flex-col justify-center items-center"
                    >
                        <button
                            className="absolute top-8 right-8 p-2"
                            onClick={() => setMobileMenuOpen(false)}
                        >
                            <X strokeWidth={1.5} className="w-8 h-8 hover:text-gold transition-colors" />
                        </button>
                        <div className="flex flex-col gap-8 text-center">
                            <Link to="/" onClick={() => setMobileMenuOpen(false)} className="font-heading text-4xl hover:text-gold transition-colors">Home</Link>
                            {navLinks.map((link) => (
                                <Link
                                    key={link.name}
                                    to={link.path}
                                    onClick={() => setMobileMenuOpen(false)}
                                    className="font-heading text-4xl hover:text-gold transition-colors"
                                >
                                    {link.name}
                                </Link>
                            ))}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.header>
    );
};

export default Navbar;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Volume2, VolumeX, ChevronLeft, ChevronRight } from 'lucide-react';

const reels = [
    {
        id: 1,
        video: "https://storage.googleapis.com/gtv-videos-bucket/sample/ForBiggerEscapes.mp4",
        poster: "https://images.unsplash.com/photo-1544787219-7f47ccb76574?auto=format&fit=crop&q=80",
        text: "KOTO'S FINEST LEAVES ARE PLUCKED",
    },
    {
        id: 2,
        video: "https://storage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4",
        poster: "https://images.unsplash.com/photo-1576092768241-dec231879fc3?auto=format&fit=crop&q=80",
        text: "MIST-KISSED MOUNTAIN PEAKS",
    },
    {
        id: 3,
        video: "https://storage.googleapis.com/gtv-videos-bucket/sample/ForBiggerJoyrides.mp4",
        poster: "https://images.unsplash.com/photo-1515823662972-da6a2e4d3002?auto=format&fit=crop&q=80",
        text: "CENTURIES OF CRAFTSMANSHIP",
    },
    {
        id: 4,
        video: "https://storage.googleapis.com/gtv-videos-bucket/sample/ForBiggerMeltdowns.mp4",
        poster: "https://images.unsplash.com/photo-1556679343-c7306c1976bc?auto=format&fit=crop&q=80",
        text: "THE PERFECT INFUSION",
    },
    {
        id: 5,
        video: "https://storage.googleapis.com/gtv-videos-bucket/sample/TearsOfSteel.mp4",
        poster: "https://images.unsplash.com/photo-1563822249548-9a72b6353cd1?auto=format&fit=crop&q=80",
        text: "A GROUNDING CEREMONY",
    }
];

const ReelsCarousel = () => {
    const [currentIndex, setCurrentIndex] = useState(2);
    const [isMuted, setIsMuted] = useState(true);
    const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1200);

    useEffect(() => {
        const handleResize = () => setWindowWidth(window.innerWidth);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const handleNext = () => setCurrentIndex((prev) => (prev + 1) % reels.length);
    const handlePrev = () => setCurrentIndex((prev) => (prev - 1 + reels.length) % reels.length);

    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentIndex((prev) => (prev + 1) % reels.length);
        }, 2000);
        return () => clearInterval(interval);
    }, []);

    const toggleMute = (e) => {
        e.stopPropagation();
        setIsMuted(!isMuted);
    };

    const getLayout = (relativeIndex) => {
        const isMobile = windowWidth < 768;
        const xOffset = isMobile ? 220 : 300;

        if (relativeIndex === 0) {
            return { scale: 1, x: 0, zIndex: 30, brightness: 1, opacity: 1 };
        } else if (relativeIndex === 1) {
            return { scale: 0.85, x: xOffset, zIndex: 20, brightness: 0.6, opacity: 1 };
        } else if (relativeIndex === -1) {
            return { scale: 0.85, x: -xOffset, zIndex: 20, brightness: 0.6, opacity: 1 };
        } else if (relativeIndex === 2) {
            return { scale: 0.7, x: xOffset * 1.8, zIndex: 10, brightness: 0.3, opacity: isMobile ? 0 : 1 };
        } else if (relativeIndex === -2) {
            return { scale: 0.7, x: -xOffset * 1.8, zIndex: 10, brightness: 0.3, opacity: isMobile ? 0 : 1 };
        } else {
            return { scale: 0.5, x: 0, zIndex: 0, brightness: 0, opacity: 0 };
        }
    };

    return (
        <div className="relative w-full max-w-7xl mx-auto h-[500px] md:h-[600px] flex items-center justify-center overflow-hidden">
            {reels.map((reel, index) => {
                let relativeIndex = index - currentIndex;
                // Handle circular wrapping for 5 items
                if (relativeIndex > 2) relativeIndex -= reels.length;
                if (relativeIndex < -2) relativeIndex += reels.length;

                const layout = getLayout(relativeIndex);
                const isActive = relativeIndex === 0;

                return (
                    <motion.div
                        key={reel.id}
                        initial={false}
                        animate={{
                            scale: layout.scale,
                            x: layout.x,
                            zIndex: layout.zIndex,
                            opacity: layout.opacity,
                            filter: `brightness(${layout.brightness})`
                        }}
                        transition={{ duration: 0.6, ease: [0.32, 0.72, 0, 1] }}
                        className="absolute w-[260px] md:w-[320px] h-[450px] md:h-[550px] rounded-2xl overflow-hidden cursor-pointer shadow-2xl bg-forest-dark"
                        onClick={() => {
                            if (!isActive) setCurrentIndex(index);
                        }}
                    >
                        <video
                            src={reel.video}
                            poster={reel.poster}
                            autoPlay={isActive}
                            loop
                            muted={isMuted}
                            playsInline
                            className="w-full h-full object-cover"
                        />

                        <div className="absolute inset-0 bg-gradient-to-b from-black/0 via-black/10 to-black/70 pointer-events-none" />

                        {isActive && (
                            <motion.div
                                initial={{ opacity: 0, y: 15 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: 0.3, duration: 0.5 }}
                                className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center"
                            >
                                <h3 className="text-white font-sans text-xl md:text-2xl uppercase tracking-[0.2em] font-medium leading-relaxed drop-shadow-lg">
                                    {reel.text}
                                </h3>
                            </motion.div>
                        )}

                        <button
                            onClick={toggleMute}
                            className={`absolute bottom-4 right-4 p-2.5 rounded-full bg-black/40 text-white backdrop-blur-md hover:bg-black/60 transition-colors ${!isActive && 'hidden'}`}
                        >
                            {isMuted ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                        </button>
                    </motion.div>
                );
            })}

            {/* Navigation Overlays */}
            <button
                onClick={handlePrev}
                className="absolute left-4 md:left-12 z-40 p-3 bg-white/10 hover:bg-white/30 backdrop-blur-md border border-white/20 rounded-full text-white transition-all transform hover:scale-105"
            >
                <ChevronLeft className="w-6 h-6" />
            </button>
            <button
                onClick={handleNext}
                className="absolute right-4 md:right-12 z-40 p-3 bg-white/10 hover:bg-white/30 backdrop-blur-md border border-white/20 rounded-full text-white transition-all transform hover:scale-105"
            >
                <ChevronRight className="w-6 h-6" />
            </button>
        </div>
    );
};

